{
"manifestVersion": "2026.2",
"tenantId": "tenant_global_bank_04",
"registry": {
"component.forex-widget": {
"id": "component.forex-widget",
"version": "1.4.2",
"entry": "https://cdn.platform.com/assets/modules/forex-widget@1.4.2.js",
"css": "https://cdn.platform.com/assets/modules/forex-widget@1.4.2.css",
"sri": "sha384-oqVuAfXRKap7fdgcCY5uykM6+R9GqQ8K..."
}
